import asyncio
import microcoapy
from microcoapy import CoapServer, CoapResource, CoapRequest, CoapResponse
import json

# Global state for sensors and actuators
sensor_data = {"temp": 25.0}
actuator_data = {"light": False}

class TempResource(CoapResource):
    def __init__(self):
        super().__init__("/sensors/temp")
    
    def get(self, request):
        response = CoapResponse(205, json.dumps({"temp": sensor_data["temp"]}).encode())
        response.set_content_format(50)  # JSON format
        return response
    
    def put(self, request):
        try:
            data = json.loads(request.get_payload().decode())
            sensor_data["temp"] = float(data.get("temp", sensor_data["temp"]))
            response = CoapResponse(204)
            return response
        except Exception:
            response = CoapResponse(400)
            return response

class LightResource(CoapResource):
    def __init__(self):
        super().__init__("/actuators/light")
    
    def get(self, request):
        response = CoapResponse(205, json.dumps({"light": actuator_data["light"]}).encode())
        response.set_content_format(50)  # JSON format
        return response
    
    def put(self, request):
        try:
            data = json.loads(request.get_payload().decode())
            actuator_data["light"] = bool(data.get("light", actuator_data["light"]))
            response = CoapResponse(204)
            return response
        except Exception:
            response = CoapResponse(400)
            return response

async def main():
    # Create CoAP server
    server = CoapServer()
    
    # Add resources
    server.add_resource(TempResource())
    server.add_resource(LightResource())
    
    # Start server
    await server.start()
    
    try:
        while True:
            await asyncio.sleep(1)
    except KeyboardInterrupt:
        await server.stop()

# Run the server
if __name__ == "__main__":
    asyncio.run(main())